update content_items set body_en = '{"intro":"A sample mini-lesson on the Giuoco Piano (Italian Game), to show how the Theory module works: guided steps, variations, explorer and coach.","tree":{"nodes":{"n0":{"id":"n0","parentId":null,"ply":0,"san":null,"uci":null,"fen":"rnbqkbnr/pppppppp/8/8/8/8/PPPPPPPP/RNBQKBNR w KQkq - 0 1","children":["n1"]},"n1":{"id":"n1","parentId":"n0","ply":1,"san":"e4","uci":"e2e4","fen":"rnbqkbnr/pppppppp/8/8/4P3/8/PPPP1PPP/RNBQKBNR b KQkq - 0 1","children":["n2"]},"n2":{"id":"n2","parentId":"n1","ply":2,"san":"e5","uci":"e7e5","fen":"rnbqkbnr/pppp1ppp/8/4p3/4P3/8/PPPP1PPP/RNBQKBNR w KQkq - 0 2","children":["n3"]},"n3":{"id":"n3","parentId":"n2","ply":3,"san":"Nf3","uci":"g1f3","fen":"rnbqkbnr/pppp1ppp/8/4p3/4P3/5N2/PPPP1PPP/RNBQKB1R b KQkq - 1 2","children":["n4"]},"n4":{"id":"n4","parentId":"n3","ply":4,"san":"Nc6","uci":"b8c6","fen":"r1bqkbnr/pppp1ppp/2n5/4p3/4P3/5N2/PPPP1PPP/RNBQKB1R w KQkq - 2 3","children":["n5"]},"n5":{"id":"n5","parentId":"n4","ply":5,"san":"Bc4","uci":"f1c4","fen":"r1bqkbnr/pppp1ppp/2n5/4p3/2B1P3/5N2/PPPP1PPP/RNBQK2R b KQkq - 3 3","children":["n6","n7"]},"n6":{"id":"n6","parentId":"n5","ply":6,"san":"Bc5","uci":"f8c5","fen":"r1bqk1nr/pppp1ppp/2n5/2b1p3/2B1P3/5N2/PPPP1PPP/RNBQK2R w KQkq - 4 4","children":["n9"]},"n7":{"id":"n7","parentId":"n5","ply":6,"san":"Nf6","uci":"g8f6","fen":"r1bqkb1r/pppp1ppp/2n2n2/4p3/2B1P3/5N2/PPPP1PPP/RNBQK2R w KQkq - 4 4","children":["n8"]},"n8":{"id":"n8","parentId":"n7","ply":7,"san":"Ng5","uci":"f3g5","fen":"r1bqkb1r/pppp1ppp/2n2n2/4p1N1/2B1P3/8/PPPP1PPP/RNBQK2R b KQkq - 5 4","children":[],"comment":"Two Knights Defense: 4. Ng5 immediately attacks f7, sharp play.","nags":[5]},"n9":{"id":"n9","parentId":"n6","ply":7,"san":"c3","uci":"c2c3","fen":"r1bqk1nr/pppp1ppp/2n5/2b1p3/2B1P3/2P2N2/PP1P1PPP/RNBQK2R b KQkq - 0 4","children":["n10"]},"n10":{"id":"n10","parentId":"n9","ply":8,"san":"Nf6","uci":"g8f6","fen":"r1bqk2r/pppp1ppp/2n2n2/2b1p3/2B1P3/2P2N2/PP1P1PPP/RNBQK2R w KQkq - 1 5","children":[]}},"rootId":"n0","seq":11},"steps":[{"nodeId":"n1","text":"White occupies the center and frees the bishop and queen. It is the most direct opening move.","shapes":[{"orig":"e2","dest":"e4","brush":"green"}]},{"nodeId":"n5","text":"The Italian bishop takes aim at f7, the weakest square in Black''s camp (defended only by the king). This is the idea that gives the opening its name.","shapes":[{"orig":"c4","dest":"f7","brush":"red"},{"orig":"f7","brush":"red"}],"highlightMoves":["Bc5","Nf6"]},{"nodeId":"n6","text":"Black responds symmetrically: his bishop also aims at f2. The Giuoco Piano arises, positional and balanced."},{"nodeId":"n9","text":"With c3 White prepares d4: he wants to build a big pawn center and gain space. Try deviating with another move to see what the engine says."}]}'::jsonb where slug = 'giuoco-piano-esempio';
update content_items set body_en = '{"intro":"Draft pending review. The Italian Game (Giuoco Piano): natural development and pressure on f7, then c3-d4 to build the center.","tree":{"nodes":{"n0":{"id":"n0","parentId":null,"ply":0,"san":null,"uci":null,"fen":"rnbqkbnr/pppppppp/8/8/8/8/PPPPPPPP/RNBQKBNR w KQkq - 0 1","children":["n1"]},"n1":{"id":"n1","parentId":"n0","ply":1,"san":"e4","uci":"e2e4","fen":"rnbqkbnr/pppppppp/8/8/4P3/8/PPPP1PPP/RNBQKBNR b KQkq - 0 1","children":["n2"]},"n2":{"id":"n2","parentId":"n1","ply":2,"san":"e5","uci":"e7e5","fen":"rnbqkbnr/pppp1ppp/8/4p3/4P3/8/PPPP1PPP/RNBQKBNR w KQkq - 0 2","children":["n3"]},"n3":{"id":"n3","parentId":"n2","ply":3,"san":"Nf3","uci":"g1f3","fen":"rnbqkbnr/pppp1ppp/8/4p3/4P3/5N2/PPPP1PPP/RNBQKB1R b KQkq - 1 2","children":["n4"]},"n4":{"id":"n4","parentId":"n3","ply":4,"san":"Nc6","uci":"b8c6","fen":"r1bqkbnr/pppp1ppp/2n5/4p3/4P3/5N2/PPPP1PPP/RNBQKB1R w KQkq - 2 3","children":["n5"]},"n5":{"id":"n5","parentId":"n4","ply":5,"san":"Bc4","uci":"f1c4","fen":"r1bqkbnr/pppp1ppp/2n5/4p3/2B1P3/5N2/PPPP1PPP/RNBQK2R b KQkq - 3 3","children":["n6","n7","n9"]},"n6":{"id":"n6","parentId":"n5","ply":6,"san":"Bc5","uci":"f8c5","fen":"r1bqk1nr/pppp1ppp/2n5/2b1p3/2B1P3/5N2/PPPP1PPP/RNBQK2R w KQkq - 4 4","children":["n10"]},"n7":{"id":"n7","parentId":"n5","ply":6,"san":"Nf6","uci":"g8f6","fen":"r1bqkb1r/pppp1ppp/2n2n2/4p3/2B1P3/5N2/PPPP1PPP/RNBQK2R w KQkq - 4 4","children":["n8"]},"n8":{"id":"n8","parentId":"n7","ply":7,"san":"Ng5","uci":"f3g5","fen":"r1bqkb1r/pppp1ppp/2n2n2/4p1N1/2B1P3/8/PPPP1PPP/RNBQK2R b KQkq - 5 4","children":[],"comment":"The Two Knights Defense, sharp."},"n9":{"id":"n9","parentId":"n5","ply":6,"san":"Be7","uci":"f8e7","fen":"r1bqk1nr/ppppbppp/2n5/4p3/2B1P3/5N2/PPPP1PPP/RNBQK2R w KQkq - 4 4","children":[],"comment":"more cautious."},"n10":{"id":"n10","parentId":"n6","ply":7,"san":"c3","uci":"c2c3","fen":"r1bqk1nr/pppp1ppp/2n5/2b1p3/2B1P3/2P2N2/PP1P1PPP/RNBQK2R b KQkq - 0 4","children":["n11"]},"n11":{"id":"n11","parentId":"n10","ply":8,"san":"Nf6","uci":"g8f6","fen":"r1bqk2r/pppp1ppp/2n2n2/2b1p3/2B1P3/2P2N2/PP1P1PPP/RNBQK2R w KQkq - 1 5","children":["n12"]},"n12":{"id":"n12","parentId":"n11","ply":9,"san":"d4","uci":"d2d4","fen":"r1bqk2r/pppp1ppp/2n2n2/2b1p3/2BPP3/2P2N2/PP3PPP/RNBQK2R b KQkq - 0 5","children":["n13"]},"n13":{"id":"n13","parentId":"n12","ply":10,"san":"exd4","uci":"e5d4","fen":"r1bqk2r/pppp1ppp/2n2n2/2b5/2BpP3/2P2N2/PP3PPP/RNBQK2R w KQkq - 0 6","children":["n14"]},"n14":{"id":"n14","parentId":"n13","ply":11,"san":"cxd4","uci":"c3d4","fen":"r1bqk2r/pppp1ppp/2n2n2/2b5/2BPP3/5N2/PP3PPP/RNBQK2R b KQkq - 0 6","children":["n15"]},"n15":{"id":"n15","parentId":"n14","ply":12,"san":"Bb4+","uci":"c5b4","fen":"r1bqk2r/pppp1ppp/2n2n2/8/1bBPP3/5N2/PP3PPP/RNBQK2R w KQkq - 1 7","children":["n16"]},"n16":{"id":"n16","parentId":"n15","ply":13,"san":"Nc3","uci":"b1c3","fen":"r1bqk2r/pppp1ppp/2n2n2/8/1bBPP3/2N2N2/PP3PPP/R1BQK2R b KQkq - 2 7","children":[]}},"rootId":"n0","seq":17},"steps":[{"nodeId":"n5","text":"The bishop takes aim at f7, the weakest square in Black''s camp. This is the idea that gives the Italian its name.","shapes":[{"orig":"c4","dest":"f7","brush":"red"},{"orig":"f7","brush":"red"}],"highlightMoves":["Bc5","Nf6","Be7"]},{"nodeId":"n10","text":"c3 prepares d4: White wants a big pawn center and more space.","shapes":[{"orig":"d2","dest":"d4","brush":"green"}]},{"nodeId":"n12","text":"With d4 the center is broken open: the lines open and the real game begins. Try deviating to see what the engine says."}]}'::jsonb where slug = 'italiana-giuoco-piano';
update content_items set body_en = '{"intro":"Draft pending review. The Caro-Kann: solid and instructive. Black opens for the defense with c6+d5 without locking in the light-squared bishop.","tree":{"nodes":{"n0":{"id":"n0","parentId":null,"ply":0,"san":null,"uci":null,"fen":"rnbqkbnr/pppppppp/8/8/8/8/PPPPPPPP/RNBQKBNR w KQkq - 0 1","children":["n1"]},"n1":{"id":"n1","parentId":"n0","ply":1,"san":"e4","uci":"e2e4","fen":"rnbqkbnr/pppppppp/8/8/4P3/8/PPPP1PPP/RNBQKBNR b KQkq - 0 1","children":["n2"]},"n2":{"id":"n2","parentId":"n1","ply":2,"san":"c6","uci":"c7c6","fen":"rnbqkbnr/pp1ppppp/2p5/8/4P3/8/PPPP1PPP/RNBQKBNR w KQkq - 0 2","children":["n3"]},"n3":{"id":"n3","parentId":"n2","ply":3,"san":"d4","uci":"d2d4","fen":"rnbqkbnr/pp1ppppp/2p5/8/3PP3/8/PPP2PPP/RNBQKBNR b KQkq - 0 2","children":["n4"]},"n4":{"id":"n4","parentId":"n3","ply":4,"san":"d5","uci":"d7d5","fen":"rnbqkbnr/pp2pppp/2p5/3p4/3PP3/8/PPP2PPP/RNBQKBNR w KQkq - 0 3","children":["n5","n6"]},"n5":{"id":"n5","parentId":"n4","ply":5,"san":"Nc3","uci":"b1c3","fen":"rnbqkbnr/pp2pppp/2p5/3p4/3PP3/2N5/PPP2PPP/R1BQKBNR b KQkq - 1 3","children":["n10"]},"n6":{"id":"n6","parentId":"n4","ply":5,"san":"exd5","uci":"e4d5","fen":"rnbqkbnr/pp2pppp/2p5/3P4/3P4/8/PPP2PPP/RNBQKBNR b KQkq - 0 3","children":["n7"]},"n7":{"id":"n7","parentId":"n6","ply":6,"san":"cxd5","uci":"c6d5","fen":"rnbqkbnr/pp2pppp/8/3p4/3P4/8/PPP2PPP/RNBQKBNR w KQkq - 0 4","children":["n8"]},"n8":{"id":"n8","parentId":"n7","ply":7,"san":"Bd3","uci":"f1d3","fen":"rnbqkbnr/pp2pppp/8/3p4/3P4/3B4/PPP2PPP/RNBQK1NR b KQkq - 1 4","children":["n9"]},"n9":{"id":"n9","parentId":"n8","ply":8,"san":"Nc6","uci":"b8c6","fen":"r1bqkbnr/pp2pppp/2n5/3p4/3P4/3B4/PPP2PPP/RNBQK1NR w KQkq - 2 5","children":[],"comment":"The Exchange Variation."},"n10":{"id":"n10","parentId":"n5","ply":6,"san":"dxe4","uci":"d5e4","fen":"rnbqkbnr/pp2pppp/2p5/8/3Pp3/2N5/PPP2PPP/R1BQKBNR w KQkq - 0 4","children":["n11"]},"n11":{"id":"n11","parentId":"n10","ply":7,"san":"Nxe4","uci":"c3e4","fen":"rnbqkbnr/pp2pppp/2p5/8/3PN3/8/PPP2PPP/R1BQKBNR b KQkq - 0 4","children":["n12"]},"n12":{"id":"n12","parentId":"n11","ply":8,"san":"Bf5","uci":"c8f5","fen":"rn1qkbnr/pp2pppp/2p5/5b2/3PN3/8/PPP2PPP/R1BQKBNR w KQkq - 1 5","children":["n13"]},"n13":{"id":"n13","parentId":"n12","ply":9,"san":"Ng3","uci":"e4g3","fen":"rn1qkbnr/pp2pppp/2p5/5b2/3P4/6N1/PPP2PPP/R1BQKBNR b KQkq - 2 5","children":["n14"]},"n14":{"id":"n14","parentId":"n13","ply":10,"san":"Bg6","uci":"f5g6","fen":"rn1qkbnr/pp2pppp/2p3b1/8/3P4/6N1/PPP2PPP/R1BQKBNR w KQkq - 3 6","children":["n15"]},"n15":{"id":"n15","parentId":"n14","ply":11,"san":"h4","uci":"h2h4","fen":"rn1qkbnr/pp2pppp/2p3b1/8/3P3P/6N1/PPP2PP1/R1BQKBNR b KQkq - 0 6","children":["n16"]},"n16":{"id":"n16","parentId":"n15","ply":12,"san":"h6","uci":"h7h6","fen":"rn1qkbnr/pp2ppp1/2p3bp/8/3P3P/6N1/PPP2PP1/R1BQKBNR w KQkq - 0 7","children":["n17"]},"n17":{"id":"n17","parentId":"n16","ply":13,"san":"Nf3","uci":"g1f3","fen":"rn1qkbnr/pp2ppp1/2p3bp/8/3P3P/5NN1/PPP2PP1/R1BQKB1R b KQkq - 1 7","children":["n18"]},"n18":{"id":"n18","parentId":"n17","ply":14,"san":"Nd7","uci":"b8d7","fen":"r2qkbnr/pp1nppp1/2p3bp/8/3P3P/5NN1/PPP2PP1/R1BQKB1R w KQkq - 2 8","children":[]}},"rootId":"n0","seq":19},"steps":[{"nodeId":"n4","text":"With c6 and d5 Black contests the center as in the French, but WITHOUT imprisoning the light-squared bishop: that is the merit of the Caro-Kann.","shapes":[{"orig":"d5","dest":"e4","brush":"green"}]},{"nodeId":"n12","text":"Key move: the bishop comes out ACTIVE to f5, outside the pawn chain, before playing e6. This is the difference from the French.","shapes":[{"orig":"f5","brush":"green"}]},{"nodeId":"n18","text":"The typical structure is reached: Black is solid, ready for e6, Ngf6, Bd6 and kingside castling. Explore the alternatives with the engine and the explorer."}]}'::jsonb where slug = 'caro-kann-principale';
update content_items set body_en = '{"intro":"The most elementary and most important endgame: a single pawn. Winning depends on the OPPOSITION (kings on the same file, one square between them, with the move on the opponent) and on controlling the key squares in front of the pawn. The king must precede the pawn, not push it carelessly. (Draft pending review.)","tree":{"nodes":{"n0":{"id":"n0","parentId":null,"ply":0,"san":null,"uci":null,"fen":"4k3/8/4K3/8/4P3/8/8/8 w - - 0 1","children":["n1"]},"n1":{"id":"n1","parentId":"n0","ply":1,"san":"e5","uci":"e4e5","fen":"4k3/8/4K3/4P3/8/8/8/8 b - - 0 1","children":["n2"]},"n2":{"id":"n2","parentId":"n1","ply":2,"san":"Kd8","uci":"e8d8","fen":"3k4/8/4K3/4P3/8/8/8/8 w - - 1 2","children":["n3"]},"n3":{"id":"n3","parentId":"n2","ply":3,"san":"Kf7","uci":"e6f7","fen":"3k4/5K2/8/4P3/8/8/8/8 b - - 2 2","children":["n4"]},"n4":{"id":"n4","parentId":"n3","ply":4,"san":"Kc7","uci":"d8c7","fen":"8/2k2K2/8/4P3/8/8/8/8 w - - 3 3","children":["n5"]},"n5":{"id":"n5","parentId":"n4","ply":5,"san":"e6","uci":"e5e6","fen":"8/2k2K2/4P3/8/8/8/8/8 b - - 0 3","children":["n6"]},"n6":{"id":"n6","parentId":"n5","ply":6,"san":"Kb6","uci":"c7b6","fen":"8/5K2/1k2P3/8/8/8/8/8 w - - 1 4","children":["n7"]},"n7":{"id":"n7","parentId":"n6","ply":7,"san":"e7","uci":"e6e7","fen":"8/4PK2/1k6/8/8/8/8/8 b - - 0 4","children":["n8"]},"n8":{"id":"n8","parentId":"n7","ply":8,"san":"Kc5","uci":"b6c5","fen":"8/4PK2/8/2k5/8/8/8/8 w - - 1 5","children":["n9"]},"n9":{"id":"n9","parentId":"n8","ply":9,"san":"e8=Q","uci":"e7e8q","fen":"4Q3/5K2/8/2k5/8/8/8/8 b - - 0 5","children":["n10"]},"n10":{"id":"n10","parentId":"n9","ply":10,"san":"Kd4","uci":"c5d4","fen":"4Q3/5K2/8/8/3k4/8/8/8 w - - 1 6","children":["n11"]},"n11":{"id":"n11","parentId":"n10","ply":11,"san":"Qe1","uci":"e8e1","fen":"8/5K2/8/8/3k4/8/8/4Q3 b - - 2 6","children":["n12"]},"n12":{"id":"n12","parentId":"n11","ply":12,"san":"Kd3","uci":"d4d3","fen":"8/5K2/8/8/8/3k4/8/4Q3 w - - 3 7","children":[]}},"rootId":"n0","seq":13},"steps":[{"nodeId":"n0","text":"The white king is already two ranks ahead of the pawn: that condition alone is winning. Here the pawn can run, because the king escorts it.","shapes":[{"orig":"e6","brush":"green"}]},{"nodeId":"n2","text":"The king accompanies the pawn step by step: it is the king that guarantees promotion, not a hasty push. When you lack the king''s advantage, the opposition is what matters (see above)."},{"nodeId":"n5","text":"Escorted by the king, the pawn reaches the eighth rank and promotes. The pattern to remember: in king-and-pawn endings the king comes before the pawn."}],"practice":{"fen":"4k3/8/4K3/8/4P3/8/8/8 w - - 0 1","userColor":"white","goal":"win","progressKey":"kp_vs_k","hint":"The king in front of the pawn is worth more than a hurried push: look for the key squares and the opposition."}}'::jsonb where slug = 're-e-pedone-contro-re';
update content_items set body_en = '{"intro":"The winning position par excellence in rook endings: the pawn is on the seventh rank, your own king in front, the enemy king cut off. The winning technique is the BRIDGE: you bring the rook to the fourth rank to shield against checks and let your king out. (Draft pending review.)","tree":{"nodes":{"n0":{"id":"n0","parentId":null,"ply":0,"san":null,"uci":null,"fen":"3K4/3P4/5k2/8/8/8/r7/4R3 w - - 0 1","children":["n1"]},"n1":{"id":"n1","parentId":"n0","ply":1,"san":"Ke8","uci":"d8e8","fen":"4K3/3P4/5k2/8/8/8/r7/4R3 b - - 1 1","children":["n2"]},"n2":{"id":"n2","parentId":"n1","ply":2,"san":"Rd2","uci":"a2d2","fen":"4K3/3P4/5k2/8/8/8/3r4/4R3 w - - 2 2","children":["n3"]},"n3":{"id":"n3","parentId":"n2","ply":3,"san":"d8=Q+","uci":"d7d8q","fen":"3QK3/8/5k2/8/8/8/3r4/4R3 b - - 0 2","children":["n4"]},"n4":{"id":"n4","parentId":"n3","ply":4,"san":"Rxd8+","uci":"d2d8","fen":"3rK3/8/5k2/8/8/8/8/4R3 w - - 0 3","children":["n5"]},"n5":{"id":"n5","parentId":"n4","ply":5,"san":"Kxd8","uci":"e8d8","fen":"3K4/8/5k2/8/8/8/8/4R3 b - - 0 3","children":["n6"]},"n6":{"id":"n6","parentId":"n5","ply":6,"san":"Kf5","uci":"f6f5","fen":"3K4/8/8/5k2/8/8/8/4R3 w - - 1 4","children":["n7"]},"n7":{"id":"n7","parentId":"n6","ply":7,"san":"Ke7","uci":"d8e7","fen":"8/4K3/8/5k2/8/8/8/4R3 b - - 2 4","children":["n8"]},"n8":{"id":"n8","parentId":"n7","ply":8,"san":"Kg5","uci":"f5g5","fen":"8/4K3/8/6k1/8/8/8/4R3 w - - 3 5","children":["n9"]},"n9":{"id":"n9","parentId":"n8","ply":9,"san":"Rf1","uci":"e1f1","fen":"8/4K3/8/6k1/8/8/8/5R2 b - - 4 5","children":["n10"]},"n10":{"id":"n10","parentId":"n9","ply":10,"san":"Kg6","uci":"g5g6","fen":"8/4K3/6k1/8/8/8/8/5R2 w - - 5 6","children":["n11"]},"n11":{"id":"n11","parentId":"n10","ply":11,"san":"Rf6+","uci":"f1f6","fen":"8/4K3/5Rk1/8/8/8/8/8 b - - 6 6","children":["n12"]},"n12":{"id":"n12","parentId":"n11","ply":12,"san":"Kg5","uci":"g6g5","fen":"8/4K3/5R2/6k1/8/8/8/8 w - - 7 7","children":[]}},"rootId":"n0","seq":13},"steps":[{"nodeId":"n0","text":"Pawn on the seventh rank, white king in front, black king cut off by the rook: this is the Lucena position, winning. All you need is the right technique to bring the king out without losing the pawn.","shapes":[{"orig":"d7","brush":"green"},{"orig":"e1","dest":"e4","brush":"blue"}]},{"nodeId":"n3","text":"One concrete and very strong way: promote and, after the trade of rooks, stay with Rook and King against King. In the practice below, however, you can train the bridge technique step by step."},{"nodeId":"n6","text":"What remains is a Rook and King against King ending: an elementary win. The essential thing was not to lose the pawn on the seventh rank."}],"practice":{"fen":"3K4/3P4/5k2/8/8/8/r7/4R3 w - - 0 1","userColor":"white","goal":"win","progressKey":"lucena","hint":"Build the bridge: bring the rook to the fourth rank, so you can interpose it against the checks and free your king."}}'::jsonb where slug = 'posizione-di-lucena';
update content_items set body_en = '{"intro":"The defensive method to know by heart: as long as the opponent''s pawn has not reached the sixth rank, the defending rook stays on the THIRD rank (the sixth from the attacker''s point of view) and prevents the enemy king from advancing. As soon as the pawn pushes, the rook drops behind to give checks: a draw. (Draft pending review.)","tree":{"nodes":{"n0":{"id":"n0","parentId":null,"ply":0,"san":null,"uci":null,"fen":"8/4k3/r7/3KP3/8/8/8/7R b - - 0 1","children":["n1"]},"n1":{"id":"n1","parentId":"n0","ply":1,"san":"Ra2","uci":"a6a2","fen":"8/4k3/8/3KP3/8/8/r7/7R w - - 1 2","children":["n2"]},"n2":{"id":"n2","parentId":"n1","ply":2,"san":"e6","uci":"e5e6","fen":"8/4k3/4P3/3K4/8/8/r7/7R b - - 0 2","children":["n3"]},"n3":{"id":"n3","parentId":"n2","ply":3,"san":"Rb2","uci":"a2b2","fen":"8/4k3/4P3/3K4/8/8/1r6/7R w - - 1 3","children":["n4"]},"n4":{"id":"n4","parentId":"n3","ply":4,"san":"Ra1","uci":"h1a1","fen":"8/4k3/4P3/3K4/8/8/1r6/R7 b - - 2 3","children":["n5"]},"n5":{"id":"n5","parentId":"n4","ply":5,"san":"Rc2","uci":"b2c2","fen":"8/4k3/4P3/3K4/8/8/2r5/R7 w - - 3 4","children":["n6"]},"n6":{"id":"n6","parentId":"n5","ply":6,"san":"Rb1","uci":"a1b1","fen":"8/4k3/4P3/3K4/8/8/2r5/1R6 b - - 4 4","children":["n7"]},"n7":{"id":"n7","parentId":"n6","ply":7,"san":"Ra2","uci":"c2a2","fen":"8/4k3/4P3/3K4/8/8/r7/1R6 w - - 5 5","children":["n8"]},"n8":{"id":"n8","parentId":"n7","ply":8,"san":"Rc1","uci":"b1c1","fen":"8/4k3/4P3/3K4/8/8/r7/2R5 b - - 6 5","children":["n9"]},"n9":{"id":"n9","parentId":"n8","ply":9,"san":"Rb2","uci":"a2b2","fen":"8/4k3/4P3/3K4/8/8/1r6/2R5 w - - 7 6","children":["n10"]},"n10":{"id":"n10","parentId":"n9","ply":10,"san":"Ra1","uci":"c1a1","fen":"8/4k3/4P3/3K4/8/8/1r6/R7 b - - 8 6","children":[]}},"rootId":"n0","seq":11},"steps":[{"nodeId":"n0","text":"The defender (Black) must draw. With the opponent''s king already active on the fifth rank, the rook prepares to strike from afar: the pawn cannot break through on its own.","shapes":[{"orig":"e5","brush":"red"}]},{"nodeId":"n4","text":"As soon as the pawn advances (e6), the rook showers the king with checks from behind: there is no shelter. It''s a draw. (When the pawn is further back, you first keep the rook on the sixth rank: see above.)"}],"practice":{"fen":"8/4k3/r7/3KP3/8/8/8/7R b - - 0 1","userColor":"black","goal":"draw","progressKey":"philidor","hint":"Keep the rook on the sixth rank until the pawn pushes; then drop down to give checks from behind."}}'::jsonb where slug = 'posizione-di-philidor';
update content_items set body_en = '{"intro":"The checkmates every player must execute without hesitation. With the queen you drive the enemy king toward the edge while keeping a knight''s-move distance to avoid stalemate; with the rook you build the \"staircase\". Here you practice the queen mate; in the line you see the pattern. (Draft pending review.)","tree":{"nodes":{"n0":{"id":"n0","parentId":null,"ply":0,"san":null,"uci":null,"fen":"4k3/8/4K3/8/8/8/3Q4/8 w - - 0 1","children":["n1"]},"n1":{"id":"n1","parentId":"n0","ply":1,"san":"Qb2","uci":"d2b2","fen":"4k3/8/4K3/8/8/8/1Q6/8 b - - 1 1","children":["n2"]},"n2":{"id":"n2","parentId":"n1","ply":2,"san":"Kd8","uci":"e8d8","fen":"3k4/8/4K3/8/8/8/1Q6/8 w - - 2 2","children":["n3"]},"n3":{"id":"n3","parentId":"n2","ply":3,"san":"Qb8#","uci":"b2b8","fen":"1Q1k4/8/4K3/8/8/8/8/8 b - - 3 2","children":[]}},"rootId":"n0","seq":4},"steps":[{"nodeId":"n0","text":"With queen and king against a lone king, the mate is extremely quick. The queen confines the enemy king toward the edge; your own king comes closer to deliver the final blow.","shapes":[{"orig":"d2","brush":"green"}]},{"nodeId":"n2","text":"Qb8#: mate on the edge. Notice how the queen takes away squares and drives the king onto the back rank — but always watch out for STALEMATE when the enemy king has few squares and your king is far away."}],"practice":{"fen":"4k3/8/4K3/8/8/8/3Q4/8 w - - 0 1","userColor":"white","goal":"win","progressKey":"kq_vs_k","hint":"Bring the queen to a knight''s-move distance from the enemy king to confine it, bring your king up in support, and watch out for stalemate."}}'::jsonb where slug = 'matti-elementari';
update content_items set body_en = '{"intro":"The queen wins against a pawn on the seventh rank if it is a central or knight''s pawn: with checks and attacks you gain the tempo to bring your king up, forcing the enemy king in front of the pawn. With a rook''s pawn or a bishop''s pawn there are stalemate tricks and it is often a draw. Here we have a central pawn: won. (Draft pending review.)","tree":{"nodes":{"n0":{"id":"n0","parentId":null,"ply":0,"san":null,"uci":null,"fen":"Q7/8/5K2/8/8/8/3p4/3k4 w - - 0 1","children":["n1"]},"n1":{"id":"n1","parentId":"n0","ply":1,"san":"Ke5","uci":"f6e5","fen":"Q7/8/8/4K3/8/8/3p4/3k4 b - - 1 1","children":["n2"]},"n2":{"id":"n2","parentId":"n1","ply":2,"san":"Kc1","uci":"d1c1","fen":"Q7/8/8/4K3/8/8/3p4/2k5 w - - 2 2","children":["n3"]},"n3":{"id":"n3","parentId":"n2","ply":3,"san":"Qa1+","uci":"a8a1","fen":"8/8/8/4K3/8/8/3p4/Q1k5 b - - 3 2","children":["n4"]},"n4":{"id":"n4","parentId":"n3","ply":4,"san":"Kc2","uci":"c1c2","fen":"8/8/8/4K3/8/8/2kp4/Q7 w - - 4 3","children":["n5"]},"n5":{"id":"n5","parentId":"n4","ply":5,"san":"Qa4+","uci":"a1a4","fen":"8/8/8/4K3/Q7/8/2kp4/8 b - - 5 3","children":["n6"]},"n6":{"id":"n6","parentId":"n5","ply":6,"san":"Kc1","uci":"c2c1","fen":"8/8/8/4K3/Q7/8/3p4/2k5 w - - 6 4","children":["n7"]},"n7":{"id":"n7","parentId":"n6","ply":7,"san":"Qc4+","uci":"a4c4","fen":"8/8/8/4K3/2Q5/8/3p4/2k5 b - - 7 4","children":["n8"]},"n8":{"id":"n8","parentId":"n7","ply":8,"san":"Kb1","uci":"c1b1","fen":"8/8/8/4K3/2Q5/8/3p4/1k6 w - - 8 5","children":["n9"]},"n9":{"id":"n9","parentId":"n8","ply":9,"san":"Qb3+","uci":"c4b3","fen":"8/8/8/4K3/8/1Q6/3p4/1k6 b - - 9 5","children":["n10"]},"n10":{"id":"n10","parentId":"n9","ply":10,"san":"Kc1","uci":"b1c1","fen":"8/8/8/4K3/8/1Q6/3p4/2k5 w - - 10 6","children":["n11"]},"n11":{"id":"n11","parentId":"n10","ply":11,"san":"Qc3+","uci":"b3c3","fen":"8/8/8/4K3/8/2Q5/3p4/2k5 b - - 11 6","children":["n12"]},"n12":{"id":"n12","parentId":"n11","ply":12,"san":"Kd1","uci":"c1d1","fen":"8/8/8/4K3/8/2Q5/3p4/3k4 w - - 12 7","children":["n13"]},"n13":{"id":"n13","parentId":"n12","ply":13,"san":"Ke4","uci":"e5e4","fen":"8/8/8/8/4K3/2Q5/3p4/3k4 b - - 13 7","children":["n14"]},"n14":{"id":"n14","parentId":"n13","ply":14,"san":"Ke2","uci":"d1e2","fen":"8/8/8/8/4K3/2Q5/3pk3/8 w - - 14 8","children":[]}},"rootId":"n0","seq":15},"steps":[{"nodeId":"n0","text":"A central pawn on the seventh rank: the queen wins. The method is a series of checks that forces the black king IN FRONT of its own pawn, blocking it for a tempo.","shapes":[{"orig":"d2","brush":"red"}]},{"nodeId":"n4","text":"Each check gains a tempo: when the king is pinned in front of the pawn, the white king comes closer (Ke5-e4...). By repeating the pattern, the king arrives and the game is won."}],"practice":{"fen":"Q7/8/5K2/8/8/8/3p4/3k4 w - - 0 1","userColor":"white","goal":"win","progressKey":"q_vs_p","hint":"Alternate checks and attacks on the pawn to force the enemy king in front of it: that way you gain the tempo to bring your king closer."}}'::jsonb where slug = 'donna-contro-pedone';
update content_items set body_en = '{"intro":"The isolated queen''s pawn (here White''s d4 pawn, with no c- or e-pawns to support it) is strength and weakness at once: it gives space, active squares (e5, c5) and the initiative for an attack, but in an endgame it becomes a target. The side that has it plays for ACTIVITY; the side facing it BLOCKS the square in front (d5) and aims for trades. (Draft pending review.)","tree":{"nodes":{"n0":{"id":"n0","parentId":null,"ply":0,"san":null,"uci":null,"fen":"r1bq1rk1/pp3ppp/2n1pn2/8/1bBP4/2N2N2/PP3PPP/R1BQ1RK1 w - - 1 10","children":["n1"]},"n1":{"id":"n1","parentId":"n0","ply":1,"san":"Re1","uci":"f1e1","fen":"r1bq1rk1/pp3ppp/2n1pn2/8/1bBP4/2N2N2/PP3PPP/R1BQR1K1 b - - 2 10","children":["n2"]},"n2":{"id":"n2","parentId":"n1","ply":2,"san":"b6","uci":"b7b6","fen":"r1bq1rk1/p4ppp/1pn1pn2/8/1bBP4/2N2N2/PP3PPP/R1BQR1K1 w - - 0 11","children":["n3"]},"n3":{"id":"n3","parentId":"n2","ply":3,"san":"a3","uci":"a2a3","fen":"r1bq1rk1/p4ppp/1pn1pn2/8/1bBP4/P1N2N2/1P3PPP/R1BQR1K1 b - - 0 11","children":["n4"]},"n4":{"id":"n4","parentId":"n3","ply":4,"san":"Bxc3","uci":"b4c3","fen":"r1bq1rk1/p4ppp/1pn1pn2/8/2BP4/P1b2N2/1P3PPP/R1BQR1K1 w - - 0 12","children":["n5"]},"n5":{"id":"n5","parentId":"n4","ply":5,"san":"bxc3","uci":"b2c3","fen":"r1bq1rk1/p4ppp/1pn1pn2/8/2BP4/P1P2N2/5PPP/R1BQR1K1 b - - 0 12","children":[]}},"rootId":"n0","seq":6},"steps":[{"nodeId":"n0","text":"Here is the typical structure: the d4 pawn is isolated (no c- or e-pawns). It gives White space and active squares, but it must be supported with pieces, never traded in an endgame.","shapes":[{"orig":"d4","brush":"blue"}]},{"nodeId":"n1","text":"The rooks belong on the half-open files (c and e) and the pieces on the strong squares; the long-term idea is the d4-d5 break at the right moment."}],"exercise":{"fen":"r1bq1rk1/pp3ppp/2n1pn2/8/1bBP4/2N2N2/PP3PPP/R1BQ1RK1 w - - 1 10","userColor":"white","prompt":"White has the IQP on d4. Find a move consistent with the plan: piece activity and pressure, NOT a hasty push. What do you propose?","planHint":"With the IQP you play for the initiative: place your pieces on active squares (Ne5, bishop on d3 aimed at h7, rooks on c1/e1) and prepare, at the right moment, the d4-d5 break that frees the isolani and opens the game. Avoid trades that would leave you in an endgame with the weak pawn.","relatedTacticsTheme":"kingsideAttack","progressKey":"isolani_dama"}}'::jsonb where slug = 'pedone-isolano-di-donna-iqp';
update content_items set body_en = '{"intro":"Rooks live on open files. The side that seizes the open file (here the c-file, with no pawns) and brings its rooks there threatens the INVASION of the seventh rank, where it attacks the opponent''s pawns and ties down their pieces. If possible, you double the rooks before invading. (Draft pending review.)","tree":{"nodes":{"n0":{"id":"n0","parentId":null,"ply":0,"san":null,"uci":null,"fen":"2r3k1/pp3ppp/4p3/3p4/3P4/4P3/PP3PPP/2R3K1 w - - 0 1","children":["n1"]},"n1":{"id":"n1","parentId":"n0","ply":1,"san":"Rc5","uci":"c1c5","fen":"2r3k1/pp3ppp/4p3/2Rp4/3P4/4P3/PP3PPP/6K1 b - - 1 1","children":["n2"]},"n2":{"id":"n2","parentId":"n1","ply":2,"san":"Rxc5","uci":"c8c5","fen":"6k1/pp3ppp/4p3/2rp4/3P4/4P3/PP3PPP/6K1 w - - 0 2","children":["n3"]},"n3":{"id":"n3","parentId":"n2","ply":3,"san":"dxc5","uci":"d4c5","fen":"6k1/pp3ppp/4p3/2Pp4/8/4P3/PP3PPP/6K1 b - - 0 2","children":[]}},"rootId":"n0","seq":4},"steps":[{"nodeId":"n0","text":"The c-file is open: whoever controls it lays down the law. The rook aims for the seventh rank (c7), where the black pawns become targets.","shapes":[{"orig":"c1","dest":"c8","brush":"blue"},{"orig":"c7","brush":"green"}]}],"exercise":{"fen":"2r3k1/pp3ppp/4p3/3p4/3P4/4P3/PP3PPP/2R3K1 w - - 0 1","userColor":"white","prompt":"The c-file is open and the rooks face each other. Find a plan for White to exploit the file and aim for the seventh rank.","planHint":"Contest and seize the open file: if Black gives it up, Rc7 invades the seventh rank and attacks the pawns. If the opponent stays, consider trades that clear your path to c7, and centralize the king with the endgame in mind.","progressKey":"colonna_aperta"}}'::jsonb where slug = 'colonna-aperta-e-settima-traversa';
update content_items set body_en = '{"intro":"A weak square is a square the opponent can no longer defend with a pawn. If it is in the enemy''s half of the board and you can support it with a pawn, it becomes an OUTPOST: the ideal spot for a knight, which from there dominates without being able to be driven away. Here White has a permanent outpost on d5 (Sveshnikov-type structure). (Draft pending review.)","tree":{"nodes":{"n0":{"id":"n0","parentId":null,"ply":0,"san":null,"uci":null,"fen":"r1bq1rk1/5pbp/p1np1p2/1p1Np3/4P3/N1P5/PP3PPP/R2QKB1R w KQ - 1 12","children":["n1"]},"n1":{"id":"n1","parentId":"n0","ply":1,"san":"Nc2","uci":"a3c2","fen":"r1bq1rk1/5pbp/p1np1p2/1p1Np3/4P3/2P5/PPN2PPP/R2QKB1R b KQ - 2 12","children":["n2"]},"n2":{"id":"n2","parentId":"n1","ply":2,"san":"Be6","uci":"c8e6","fen":"r2q1rk1/5pbp/p1npbp2/1p1Np3/4P3/2P5/PPN2PPP/R2QKB1R w KQ - 3 13","children":["n3"]},"n3":{"id":"n3","parentId":"n2","ply":3,"san":"Nce3","uci":"c2e3","fen":"r2q1rk1/5pbp/p1npbp2/1p1Np3/4P3/2P1N3/PP3PPP/R2QKB1R b KQ - 4 13","children":[]}},"rootId":"n0","seq":4},"steps":[{"nodeId":"n0","text":"The knight on d5 is a perfect outpost: no black pawn can chase it away. It is the classic \"good knight\" against Black''s bishop, hemmed in by its own pawns.","shapes":[{"orig":"d5","brush":"green"}]},{"nodeId":"n1","text":"White is in no hurry: it consolidates the outpost and maneuvers the pieces onto the weak squares in Black''s camp, where the knight reigns."}],"exercise":{"fen":"r1bq1rk1/5pbp/p1np1p2/1p1Np3/4P3/N1P5/PP3PPP/R2QKB1R w KQ - 1 12","userColor":"white","prompt":"White''s knight dominates the d5 outpost, while Black has a weakened structure. Find a plan to consolidate and exploit the positional advantage.","planHint":"The outpost on d5 is permanent: no black pawn can drive it away. White''s plan is to consolidate it (maneuver Nb1-d2-f1-e3 or c3 + Nc2-e3) and play on the weak squares; the strong knight is worth more than Black''s bishop, hemmed in by its own pawns. Aim to open a second front while keeping the blockade on d5.","progressKey":"avamposti"}}'::jsonb where slug = 'case-deboli-e-avamposti';
update traps set body_en = '{"intro":"Draft pending review. Légal''s Mate: White sacrifices the queen with Nxe5, and if Black takes it, mate follows with the knight.","tree":{"nodes":{"n0":{"id":"n0","parentId":null,"ply":0,"san":null,"uci":null,"fen":"r2qkbnr/ppp2ppp/2np4/4N3/2B1P1b1/2N5/PPPP1PPP/R1BQK2R b KQkq - 0 5","children":["n1","n5"]},"n1":{"id":"n1","parentId":"n0","ply":1,"san":"Bxd1","uci":"g4d1","fen":"r2qkbnr/ppp2ppp/2np4/4N3/2B1P3/2N5/PPPP1PPP/R1BbK2R w KQkq - 0 6","children":["n2"]},"n2":{"id":"n2","parentId":"n1","ply":2,"san":"Bxf7+","uci":"c4f7","fen":"r2qkbnr/ppp2Bpp/2np4/4N3/4P3/2N5/PPPP1PPP/R1BbK2R b KQkq - 0 6","children":["n3"]},"n3":{"id":"n3","parentId":"n2","ply":3,"san":"Ke7","uci":"e8e7","fen":"r2q1bnr/ppp1kBpp/2np4/4N3/4P3/2N5/PPPP1PPP/R1BbK2R w KQ - 1 7","children":["n4"]},"n4":{"id":"n4","parentId":"n3","ply":4,"san":"Nd5#","uci":"c3d5","fen":"r2q1bnr/ppp1kBpp/2np4/3NN3/4P3/8/PPPP1PPP/R1BbK2R b KQ - 2 7","children":[]},"n5":{"id":"n5","parentId":"n0","ply":1,"san":"dxe5","uci":"d6e5","fen":"r2qkbnr/ppp2ppp/2n5/4p3/2B1P1b1/2N5/PPPP1PPP/R1BQK2R w KQkq - 0 6","children":["n6"]},"n6":{"id":"n6","parentId":"n5","ply":2,"san":"Qxg4","uci":"d1g4","fen":"r2qkbnr/ppp2ppp/2n5/4p3/2B1P1Q1/2N5/PPPP1PPP/R1B1K2R b KQkq - 0 6","children":[],"comment":"Black declines the queen and loses only a pawn."}},"rootId":"n0","seq":7},"steps":[{"nodeId":"n1","text":"The bait: grabbing the queen with Bxd1 looks like it wins material, but it ignores the mating net on f7.","shapes":[{"orig":"f7","brush":"red"}]},{"nodeId":"n2","text":"The strike: the bishop sacrifice with check drags the king out into the open.","shapes":[{"orig":"c4","dest":"f7","brush":"green"}]},{"nodeId":"n4","text":"The finish: Nd5 is mate — the knight on e5 covers d7 and f7, and the bishop blocks the escape.","shapes":[{"orig":"c3","dest":"d5","brush":"green"}]}]}'::jsonb where slug = 'matto-di-legal';
